+import { $internal } from '../common';
+import { isRelation } from '../relation/utils/is-relation';
+import type { Trait } from '../trait/types';
+import type { Aspect, AspectRecord } from './types';
+
+let aspectId = 0;
+
+export function isAspect(value: unknown): value is Aspect {
+    return !!(value as Aspect | undefined)?.traits && typeof (value as Aspect).id === 'number';
+}
+
+/** Creates a composite trait view. Constituents are always flattened. */
+export function createAspect<T extends readonly [Trait, Trait, ...Trait[]]>(
+    ...inputs: T
+): Aspect<readonly Trait[]> {
+    const traits: Trait[] = [];
+    const fields = new Set<string>();
+    const schema: Record<string, unknown> = {};
+
+    for (const input of inputs) {
+        const nested = isAspect(input) ? input.traits : [input];
+        for (const constituent of nested) {
+            if (isRelation(constituent) || constituent[$internal].relation) {
+                throw new Error('Aspects cannot contain relation traits');
+            }
+            for (const field of Object.keys(constituent.schema)) {
+                if (fields.has(field)) {
+                    throw new Error(`Aspect constituents cannot share the field "${field}"`);
+                }
+                fields.add(field);
+                schema[field] = (constituent.schema as Record<string, unknown>)[field];
+            }
+            traits.push(constituent);
+        }
+    }
+
+    const id = aspectId++;
+    const aspect = Object.assign(
+        (params: Partial<AspectRecord<readonly Trait[]>> = {}) => [aspect, params] as const,
+        { id, traits: Object.freeze(traits), schema: Object.freeze(schema) }
+    ) as Aspect<readonly Trait[]>;
+    return Object.freeze(aspect);
+}
